queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?locationname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasLocations ?child ; p:hasWar_Correspondents ?parent . } GROUP BY ?child }
  ?child p:locationName ?locationname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :War_Correspondents } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?locationname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasLocations ?child ; p:hasWar_Correspondents ?parent . } GROUP BY ?child }
  ?child p:locationName ?locationname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :War_Correspondents } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?locationname WHERE {
  ?war_correspondents_locations a :War_Correspondents_Locations .
  ?locations a :Locations .
  ?war_correspondents_locations p:hasLocations ?locations .
  ?war_correspondents a :War_Correspondents .
  ?war_correspondents_locations p:hasWar_Correspondents ?war_correspondents .
  ?war_correspondents p:name ?name .
  ?locations p:locationName ?locationname .
} }
}
